import rclpy
from rclpy.node import Node
import random

from turtlesim_custom_msgs.srv import Velocity  
from turtlesim_custom_msgs.srv import Threshold

class VelocityServiceNode(Node):
    def __init__(self):
        super().__init__('velocity_service_node')
        self.srv = self.create_service(Velocity, 'AvgVelocity', self.handle_service)
        self.get_logger().info('Velocity service ready.')

        
        self.get_logger().info('Threshold service ready.')

    def handle_service(self, request, response):
        
        return response

    def handle_threshold_service(self, request, response):
        self.threshold_ = request.threshold
        response.newthreshold = self.threshold_ 
        self.get_logger().info(f'Set new threshold to {self.threshold_:.2f}')
        return response

def main(args=None):
    rclpy.init(args=args)
    node = VelocityServiceNode()
    rclpy.spin(node)
    rclpy.shutdown()

if __name__ == '__main__':
    main()